// Read-only HBM streaming microbenchmark for AMD CDNA GPUs.
//
// The source allocation is 4 GiB, substantially larger than any GPU cache.
// Each launch visits every 16-byte uint4 exactly once.  The only stores in the
// measured kernel are one 32-bit block checksum, used to make every load live.

#include <hip/hip_runtime.h>

#include <algorithm>
#include <cstdint>
#include <cstdio>
#include <cstdlib>
#include <vector>

#ifndef HBM_BLOCKS
#define HBM_BLOCKS 256
#endif

#ifndef HBM_LOADS_PER_TRIP
#define HBM_LOADS_PER_TRIP 4
#endif

#define HIP_CHECK(call)                                                        \
  do {                                                                         \
    hipError_t _status = (call);                                               \
    if (_status != hipSuccess) {                                               \
      std::fprintf(stderr, "%s failed: %s\n", #call, hipGetErrorString(_status)); \
      return 1;                                                                \
    }                                                                          \
  } while (0)

// Four vector loads per trip provide several independent outstanding memory
// operations per thread while retaining moderate register pressure.  At each
// trip, a wave reads a contiguous 1 KiB region for each vector load.
__global__ __launch_bounds__(256, 2)
void hbm_read_stream(const uint4* __restrict__ input,
                     uint32_t* __restrict__ checksums,
                     size_t vector_count) {
  constexpr unsigned int kBlockThreads = 256;
  const size_t first = static_cast<size_t>(blockIdx.x) * kBlockThreads + threadIdx.x;
  const size_t stride = static_cast<size_t>(gridDim.x) * kBlockThreads;

  uint32_t acc = 0x9e3779b9U ^ static_cast<uint32_t>(first);

  // vector_count is deliberately an exact multiple of the unrolled stride.
  // The bound also keeps this kernel valid if that implementation detail changes.
  for (size_t i = first; i + (HBM_LOADS_PER_TRIP - 1) * stride < vector_count;
       i += HBM_LOADS_PER_TRIP * stride) {
    const uint4 a = input[i];
    const uint4 b = input[i + stride];
    const uint4 c = input[i + 2 * stride];
    const uint4 d = input[i + 3 * stride];
    acc ^= a.x ^ a.y ^ a.z ^ a.w;
    acc ^= b.x ^ b.y ^ b.z ^ b.w;
    acc ^= c.x ^ c.y ^ c.z ^ c.w;
    acc ^= d.x ^ d.y ^ d.z ^ d.w;
#if HBM_LOADS_PER_TRIP == 8
    const uint4 e = input[i + 4 * stride];
    const uint4 f = input[i + 5 * stride];
    const uint4 g = input[i + 6 * stride];
    const uint4 h = input[i + 7 * stride];
    acc ^= e.x ^ e.y ^ e.z ^ e.w;
    acc ^= f.x ^ f.y ^ f.z ^ f.w;
    acc ^= g.x ^ g.y ^ g.z ^ g.w;
    acc ^= h.x ^ h.y ^ h.z ^ h.w;
#endif
  }

  // Reduce each block.  This tiny output (4 bytes/block) prevents the compiler
  // from eliminating or narrowing any part of the read stream.
  __shared__ uint32_t sums[kBlockThreads];
  sums[threadIdx.x] = acc;
  __syncthreads();
  for (unsigned int offset = kBlockThreads / 2; offset != 0; offset >>= 1) {
    if (threadIdx.x < offset)
      sums[threadIdx.x] ^= sums[threadIdx.x + offset];
    __syncthreads();
  }
  if (threadIdx.x == 0)
    checksums[blockIdx.x] = sums[0];
}

int main() {
  constexpr size_t kBufferBytes = size_t{4} << 30;  // 4 GiB, HBM working set
  constexpr int kBlockThreads = 256;
  constexpr int kBlocks = HBM_BLOCKS;
  constexpr int kWarmupLaunches = 6;
  constexpr int kTimedLaunches = 21;
  constexpr int kLaunchesPerSample = 3;

  static_assert(kBufferBytes % sizeof(uint4) == 0, "vector aligned buffer");
  const size_t vector_count = kBufferBytes / sizeof(uint4);
  const size_t streams_per_round =
      static_cast<size_t>(kBlocks) * kBlockThreads * HBM_LOADS_PER_TRIP;
  if (vector_count % streams_per_round != 0) {
    std::fprintf(stderr, "internal launch geometry does not cover buffer exactly\n");
    return 1;
  }

  uint4* input = nullptr;
  uint32_t* checksums = nullptr;
  HIP_CHECK(hipSetDevice(0));
  HIP_CHECK(hipMalloc(&input, kBufferBytes));
  HIP_CHECK(hipMalloc(&checksums, kBlocks * sizeof(*checksums)));

  // Materialize the allocation before timing.  A non-zero byte pattern avoids
  // a special all-zero allocation while the timed kernel itself remains read-only.
  HIP_CHECK(hipMemset(input, 0x5a, kBufferBytes));
  HIP_CHECK(hipMemset(checksums, 0, kBlocks * sizeof(*checksums)));

  dim3 grid(kBlocks);
  dim3 block(kBlockThreads);
  for (int i = 0; i < kWarmupLaunches; ++i) {
    hipLaunchKernelGGL(hbm_read_stream, grid, block, 0, 0, input, checksums, vector_count);
  }
  HIP_CHECK(hipGetLastError());
  HIP_CHECK(hipDeviceSynchronize());

  hipEvent_t start, stop;
  HIP_CHECK(hipEventCreate(&start));
  HIP_CHECK(hipEventCreate(&stop));
  static_assert(kTimedLaunches % kLaunchesPerSample == 0, "whole timing samples");
  std::vector<float> milliseconds;
  milliseconds.reserve(kTimedLaunches / kLaunchesPerSample);
  for (int sample = 0; sample < kTimedLaunches / kLaunchesPerSample; ++sample) {
    HIP_CHECK(hipEventRecord(start, 0));
    for (int launch = 0; launch < kLaunchesPerSample; ++launch) {
      hipLaunchKernelGGL(hbm_read_stream, grid, block, 0, 0, input, checksums, vector_count);
      HIP_CHECK(hipGetLastError());
    }
    HIP_CHECK(hipEventRecord(stop, 0));
    HIP_CHECK(hipEventSynchronize(stop));
    float elapsed_ms = 0.0f;
    HIP_CHECK(hipEventElapsedTime(&elapsed_ms, start, stop));
    milliseconds.push_back(elapsed_ms / kLaunchesPerSample);
  }

  std::sort(milliseconds.begin(), milliseconds.end());
  const double median_ms = milliseconds[milliseconds.size() / 2];
  const double gbps = static_cast<double>(kBufferBytes) / (median_ms * 1.0e6);

  // Keep stdout machine-readable: the grading harness consumes these two lines.
  std::printf("HBM_BANDWIDTH_GBPS=%.3f\n", gbps);
  std::printf("buffer_bytes=%zu\n", kBufferBytes);
  std::fflush(stdout);

  (void)hipEventDestroy(start);
  (void)hipEventDestroy(stop);
  (void)hipFree(checksums);
  (void)hipFree(input);
  return 0;
}
